import React from 'react';
import ExpandDownFilled from '@universe-design/icons-react/ExpandDownFilled';
import { forwardHTMLRef } from '../../../util/forwardRef';
import { useCssScope } from '../../../config-provider/hooks';

export const ExpandableExpandDownFilled = forwardHTMLRef<{ isExpanded: boolean }, 'span'>(
  ({ isExpanded, ...props }, ref) => {
    const cssScope = useCssScope('expandButton');
    return (
      <ExpandDownFilled
        ref={ref}
        {...props}
        className={cssScope('__icon')}
        style={{ transform: isExpanded ? '' : 'rotate(-90deg)' }}
      />
    );
  },
);
